class Solution {
    public int[] sortArrayByParity(int[] nums) {
        Arrays.sort(nums);
        int oddIndex = 0;
        int evenIndex = 0;
        for (int i = 0; i < nums.length; i++) {
            if (nums[i] % 2 == 0) {
                nums[evenIndex++] = nums[i];
            } else {
                nums[oddIndex++] = nums[i];
            }
        }
        return nums;
    }
}
```

